import React, { useState, useCallback, useEffect } from 'react';
import { PostCreator } from './components/PostCreator';
import { Preview } from './components/Preview';
import { History } from './components/History';
import { Header } from './components/Header';
import { Loader } from './components/Loader';
import { ApiKeySelector } from './components/ApiKeySelector';
import { Post, PostType } from './types';
import { generateTextPost, generateImagePost, generateVideoPost, VideoGenerationStatus } from './services/geminiService';

// This is a polyfill for aistudio, for local development
if (typeof window !== 'undefined' && !(window as any).aistudio) {
  console.log('Polyfilling window.aistudio for local development.');
  (window as any).aistudio = {
    hasSelectedApiKey: () => new Promise(resolve => resolve(true)),
    openSelectKey: () => new Promise(resolve => resolve(true)),
  };
}


const App: React.FC = () => {
    const [posts, setPosts] = useState<Post[]>([]);
    const [currentPost, setCurrentPost] = useState<Post | null>(null);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [loadingMessage, setLoadingMessage] = useState<string>('');
    const [error, setError] = useState<string | null>(null);
    const [isApiKeySelected, setIsApiKeySelected] = useState<boolean | null>(null);

    const checkApiKey = useCallback(async () => {
      try {
        const hasKey = await (window as any).aistudio.hasSelectedApiKey();
        setIsApiKeySelected(hasKey);
      } catch (e) {
        console.error("Error checking for API key:", e);
        setIsApiKeySelected(false);
      }
    }, []);

    useEffect(() => {
        checkApiKey();
    }, [checkApiKey]);

    const handleGenerate = async (prompt: string, type: PostType) => {
        setIsLoading(true);
        setError(null);
        setCurrentPost(null);

        try {
            let newPost: Post | null = null;
            if (type === PostType.TEXT) {
                setLoadingMessage('Crafting your text post...');
                const text = await generateTextPost(prompt);
                newPost = { id: Date.now().toString(), type, prompt, content: text, timestamp: new Date() };
            } else if (type === PostType.IMAGE) {
                setLoadingMessage('Generating your image...');
                const imageUrl = await generateImagePost(prompt);
                newPost = { id: Date.now().toString(), type, prompt, content: imageUrl, timestamp: new Date() };
            } else if (type === PostType.VIDEO) {
                if (!isApiKeySelected) {
                    setError("API key is required for video generation.");
                    setIsLoading(false);
                    return;
                }
                const onProgress = (status: VideoGenerationStatus) => {
                    setLoadingMessage(status.message);
                };
                const videoUrl = await generateVideoPost(prompt, onProgress);
                newPost = { id: Date.now().toString(), type, prompt, content: videoUrl, timestamp: new Date() };
            }

            if (newPost) {
                setCurrentPost(newPost);
                setPosts(prevPosts => [newPost!, ...prevPosts]);
            }
        } catch (e: any) {
            console.error("Generation failed:", e);
            const errorMessage = e.message || "An unexpected error occurred.";
            setError(errorMessage);
            if (errorMessage.includes("Requested entity was not found")) {
                 setError("Your API key is invalid. Please select a valid key to generate videos.");
                 setIsApiKeySelected(false);
            }
        } finally {
            setIsLoading(false);
            setLoadingMessage('');
        }
    };

    const handleSelectPost = (post: Post) => {
        setCurrentPost(post);
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    return (
        <div className="min-h-screen bg-brand-bg font-sans">
            <Header />
            <main className="container mx-auto p-4 md:p-8 max-w-4xl">
                {isLoading && <Loader message={loadingMessage} />}
                {error && (
                    <div className="bg-red-900 border border-red-600 text-white px-4 py-3 rounded-lg relative mb-6" role="alert">
                        <strong className="font-bold">Error: </strong>
                        <span className="block sm:inline">{error}</span>
                    </div>
                )}

                <div className="bg-brand-surface rounded-xl border border-brand-border shadow-2xl p-6 mb-8">
                     <PostCreator onGenerate={handleGenerate} isLoading={isLoading} isApiKeySelectedForVideo={isApiKeySelected} />
                </div>

                {currentPost && (
                    <div className="mb-8">
                        <h2 className="text-2xl font-bold mb-4 text-brand-text">Preview</h2>
                        <Preview post={currentPost} />
                    </div>
                )}

                {posts.length > 0 && (
                     <div className="mt-12">
                         <h2 className="text-2xl font-bold mb-4 text-brand-text">History</h2>
                        <History posts={posts} onSelectPost={handleSelectPost} />
                     </div>
                )}

                {isApiKeySelected === false && (
                    <ApiKeySelector onKeySelected={() => {
                        setIsApiKeySelected(true);
                        setError(null);
                    }}/>
                )}
            </main>
        </div>
    );
};

export default App;

