import React, { useState } from 'react';
import { PostType } from '../types';
import { Type, Image, Film, Sparkles } from 'lucide-react';

interface PostCreatorProps {
    onGenerate: (prompt: string, type: PostType) => void;
    isLoading: boolean;
    isApiKeySelectedForVideo: boolean | null;
}

const postTypeOptions = [
    { id: PostType.TEXT, name: 'Text', icon: Type },
    { id: PostType.IMAGE, name: 'Image', icon: Image },
    { id: PostType.VIDEO, name: 'Video', icon: Film },
];

export const PostCreator: React.FC<PostCreatorProps> = ({ onGenerate, isLoading, isApiKeySelectedForVideo }) => {
    const [prompt, setPrompt] = useState('');
    const [postType, setPostType] = useState<PostType>(PostType.TEXT);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (prompt.trim()) {
            onGenerate(prompt, postType);
        }
    };

    const isGenerateDisabled = isLoading || !prompt.trim() || (postType === PostType.VIDEO && !isApiKeySelectedForVideo);

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            <div>
                <label htmlFor="prompt" className="block text-sm font-medium text-brand-text-secondary mb-2">
                    What's on your mind?
                </label>
                <textarea
                    id="prompt"
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="e.g., A futuristic city skyline at sunset, cyberpunk style..."
                    className="w-full h-32 p-3 bg-brand-bg border border-brand-border rounded-lg focus:ring-2 focus:ring-brand-primary focus:border-brand-primary transition duration-200 resize-none"
                    disabled={isLoading}
                />
            </div>

            <div>
                <span className="block text-sm font-medium text-brand-text-secondary mb-2">Choose post type</span>
                <div className="grid grid-cols-3 gap-3">
                    {postTypeOptions.map((option) => {
                        const isSelected = postType === option.id;
                        const isDisabled = isLoading || (option.id === PostType.VIDEO && !isApiKeySelectedForVideo);
                        const Icon = option.icon;
                        return (
                            <button
                                key={option.id}
                                type="button"
                                onClick={() => setPostType(option.id)}
                                disabled={isDisabled}
                                className={`flex flex-col items-center justify-center p-4 border rounded-lg transition duration-200 text-center ${
                                    isSelected
                                        ? 'bg-brand-secondary/30 border-brand-primary text-brand-primary'
                                        : 'bg-brand-bg border-brand-border hover:border-brand-text-secondary'
                                } ${isDisabled ? 'opacity-50 cursor-not-allowed' : ''}`}
                            >
                                <Icon className="h-6 w-6 mb-2" />
                                <span className="text-sm font-semibold">{option.name}</span>
                            </button>
                        );
                    })}
                </div>
                {postType === PostType.VIDEO && !isApiKeySelectedForVideo && (
                     <p className="text-xs text-yellow-400 mt-2">A Google AI Studio API key is required to generate videos. The key selection dialog will appear at the bottom of the page.</p>
                )}
            </div>

            <button
                type="submit"
                disabled={isGenerateDisabled}
                className="w-full flex items-center justify-center py-3 px-4 bg-brand-primary hover:bg-brand-secondary text-white font-bold rounded-lg transition duration-200 disabled:bg-gray-500 disabled:cursor-not-allowed transform hover:scale-105"
            >
                <Sparkles className="h-5 w-5 mr-2" />
                {isLoading ? 'Generating...' : 'Generate Post'}
            </button>
        </form>
    );
};

import React from 'react';
import { Post } from '../types';
import { Download, Copy, Share2 } from 'lucide-react';

interface PreviewProps {
    post: Post;
}

export const Preview: React.FC<PreviewProps> = ({ post }) => {

    const handleCopy = (text: string) => {
        navigator.clipboard.writeText(text);
        alert('Copied to clipboard!');
    };

    const handleDownload = (url: string, filename: string) => {
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    }

    const renderContent = () => {
        switch (post.type) {
            case 'text':
                return <p className="text-brand-text-secondary whitespace-pre-wrap p-4 bg-brand-bg rounded-lg">{post.content}</p>;
            case 'image':
                return <img src={post.content} alt={post.prompt} className="rounded-lg w-full object-contain" />;
            case 'video':
                return <video src={post.content} controls className="rounded-lg w-full" />;
            default:
                return null;
        }
    };

    const renderActions = () => {
         switch (post.type) {
            case 'text':
                return (
                    <button onClick={() => handleCopy(post.content)} className="flex items-center gap-2 px-4 py-2 text-sm bg-brand-secondary hover:bg-brand-primary text-white font-semibold rounded-lg transition">
                        <Copy size={16} /> Copy Text
                    </button>
                );
            case 'image':
                 return (
                    <button onClick={() => handleDownload(post.content, `postai-image-${post.id}.png`)} className="flex items-center gap-2 px-4 py-2 text-sm bg-brand-secondary hover:bg-brand-primary text-white font-semibold rounded-lg transition">
                        <Download size={16} /> Download Image
                    </button>
                );
            case 'video':
                return (
                     <button onClick={() => handleDownload(post.content, `postai-video-${post.id}.mp4`)} className="flex items-center gap-2 px-4 py-2 text-sm bg-brand-secondary hover:bg-brand-primary text-white font-semibold rounded-lg transition">
                        <Download size={16} /> Download Video
                    </button>
                );
            default:
                return null;
        }
    }

    return (
        <div className="bg-brand-surface rounded-xl border border-brand-border shadow-lg p-6 space-y-4">
            <div className="relative">
                {renderContent()}
            </div>
             <div className="flex items-center justify-between pt-4 border-t border-brand-border">
                <p className="text-xs text-brand-text-secondary italic truncate pr-4">Prompt: "{post.prompt}"</p>
                <div className="flex items-center gap-2">
                    {renderActions()}
                    {navigator.share && (
                        <button onClick={() => navigator.share({ title: 'PostAI Creation', text: post.prompt, url: post.content })} className="flex items-center gap-2 px-4 py-2 text-sm bg-gray-600 hover:bg-gray-500 text-white font-semibold rounded-lg transition">
                            <Share2 size={16}/> Share
                        </button>
                    )}
                </div>
            </div>
        </div>
    );
};

